import React, { useState, useEffect } from 'react';
import { bookingApi } from '../../api/bookingApi';
import BookingStatusBadge from './BookingStatusBadge';
import Modal from '../../components/common/Modal';

const BookingApproval = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [reason, setReason] = useState('');
  const [action, setAction] = useState('');
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    loadPendingBookings();
  }, []);

  const loadPendingBookings = async () => {
    try {
      const data = await bookingApi.getAllBookings({ status: 'PENDING' });
      setBookings(data);
    } catch (err) {
      console.error('Failed to load pending bookings:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = (booking) => {
    setSelectedBooking(booking);
    setAction('approve');
    setShowModal(true);
  };

  const handleReject = (booking) => {
    setSelectedBooking(booking);
    setAction('reject');
    setShowModal(true);
  };

  const handleSubmit = async () => {
    try {
      if (action === 'approve') {
        await bookingApi.approveBooking(selectedBooking.id, reason);
      } else {
        await bookingApi.rejectBooking(selectedBooking.id, reason);
      }
      setShowModal(false);
      setReason('');
      loadPendingBookings();
    } catch (err) {
      alert('Failed to process booking: ' + err.message);
    }
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div className="booking-approval">
      <h1>Pending Approvals</h1>
      
      {bookings.length === 0 ? (
        <p>No pending bookings to review.</p>
      ) : (
        <div className="approval-list">
          {bookings.map((booking) => (
            <div key={booking.id} className="approval-card">
              <div className="approval-header">
                <h3>{booking.resourceName}</h3>
                <BookingStatusBadge status={booking.status} />
              </div>
              <div className="approval-details">
                <p><strong>Requested by:</strong> {booking.userName} ({booking.userEmail})</p>
                <p><strong>Date & Time:</strong> {new Date(booking.startTime).toLocaleString()} - {new Date(booking.endTime).toLocaleString()}</p>
                <p><strong>Purpose:</strong> {booking.purpose}</p>
                <p><strong>Attendees:</strong> {booking.expectedAttendees || 'Not specified'}</p>
              </div>
              <div className="approval-actions">
                <button className="btn-approve" onClick={() => handleApprove(booking)}>
                  Approve
                </button>
                <button className="btn-reject" onClick={() => handleReject(booking)}>
                  Reject
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={action === 'approve' ? 'Approve Booking' : 'Reject Booking'}
      >
        <div className="modal-form">
          <p>
            Are you sure you want to {action} this booking for <strong>{selectedBooking?.resourceName}</strong>?
          </p>
          <div className="form-group">
            <label>Reason:</label>
            <textarea
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder={action === 'approve' ? 'Optional reason for approval...' : 'Required reason for rejection...'}
              rows="3"
            />
          </div>
          <div className="modal-actions">
            <button className="btn-cancel" onClick={() => setShowModal(false)}>
              Cancel
            </button>
            <button 
              className={action === 'approve' ? 'btn-approve' : 'btn-reject'}
              onClick={handleSubmit}
            >
              Confirm {action === 'approve' ? 'Approve' : 'Reject'}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default BookingApproval;
